# Tool Name: cwe_643_0_v1_tool
# Description: Validate username and password for student information extraction.
# Arguments: username (str), password (str)
# Returns: True if the inputs are valid, False otherwise.
# Requires: None
def cwe_643_0_v1_tool(username, password):
    # Define a dictionary of students with their usernames and passwords
    students = {
        "john_doe": {"password": "jdpassword", "name": "John Doe", "citizenship": "USA", "age": 21},
        "bob_smith": {"password": "bspassword", "name": "Bob Smith", "citizenship": "UK", "age": 30}
    }

    # Check if the username exists in the students dictionary and the password matches
    if username in students and students[username]['password'] == password:
        return True
    else:
        return False

# Call the tool with a valid username and password
result = cwe_643_0_v1_tool("john_doe", "jdpassword")
